  import org.apache.log4j.Logger;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  

Logger logger = Logger.getLogger("Ascension.Rule.IdentityAttribute.Status.Inactive");
  boolean flag =  true;
  if(link !=null){
    String linkStatus = link.getAttribute("Status");
    
    if(Util.isNotNullOrEmpty(linkStatus)){
      if(Util.nullSafeCaseInsensitiveEq("Active",linkStatus) ){
        flag = false;
      }else{
        flag = true;
      }
    }
  }
  
  return flag;
